-- ── Bolt CMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bolt CMS is a free, open-source PHP content management system built on Symfony and Twig, usable as a traditional or headless CMS.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$The Hague, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Dutch$q$]::text[],
  seo_title = COALESCE($q$Bolt CMS: Open-Source PHP Content Management System$q$, seo_title),
  seo_meta_description = COALESCE($q$Bolt CMS is a free, self-hosted, open-source PHP CMS built on Symfony and Twig. Use it as a traditional or headless content management system.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bolt CMS is a free, open-source content management system written in PHP, originally created in 2012 by Bob den Otter, a Dutch developer and founder of the web agency Two Kings in The Hague, Netherlands. Bolt was built as a lighter, simpler alternative to larger PHP CMS platforms like WordPress and Drupal, with an emphasis on developer ergonomics and ease of setup. The codebase evolved from Silex and, in later major versions, moved to the Symfony framework, using Doctrine for the database layer and Twig as its templating engine, with support for SQLite, MySQL, and PostgreSQL databases. Bolt can be run as a conventional server-rendered CMS or as a headless/decoupled CMS via API-Platform, giving developers the option to pair it with any frontend framework. The software is MIT licensed and self-hosted, meaning there is no subscription fee; organizations install and run it on their own server or hosting infrastructure and are responsible for their own hosting costs. Bolt's editor interface is available in roughly 15 languages, and the platform is extensible through custom code and Composer-installable extensions. Two Kings, the Dutch agency Bob den Otter founded in 2004, served as the primary steward of Bolt CMS for most of its history. Following Bob den Otter's death in January 2024, Two Kings was acquired in May 2024 by Ontwerpwerk, another Dutch agency, specifically to ensure continuity of the Bolt project; development has since continued through community contributions, including dependency updates and incremental feature work on the current Bolt 6.x line, which is the only officially supported release series. Bolt CMS is best suited to developers and small-to-mid-size agencies who want a lightweight, code-friendly PHP CMS for building and maintaining marketing sites, blogs, and content-driven web applications without the overhead of a larger platform, and who are comfortable managing their own server environment since there is no hosted SaaS version. Because it is fully open source with no official cloud-hosted tier, Bolt has no proprietary pricing plans, enterprise support contracts, or vendor lock-in; support comes primarily from community documentation, the GitHub/Codeberg repositories, and community channels rather than a dedicated commercial support team. It competes in the same space as other open-source, self-hosted PHP CMS options for developers who prioritize a smaller footprint and Symfony/Twig familiarity over the larger ecosystems of WordPress or Drupal. Before creating Bolt, den Otter had already built Pivot and later PivotX, blogging software widely used within the Dutch blogging community, giving him direct experience building content-publishing tools prior to starting the Bolt project in 2012.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ddf71270-678f-48af-a74a-407a4c5982bb';

