-- ── Bolt.new ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bolt.new is StackBlitz's AI app builder that generates and runs full-stack web apps in the browser from a text prompt, using WebContainers.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$50-100 employees (StackBlitz)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bolt.new Review 2026: AI App Builder Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Bolt.new is StackBlitz's AI app builder for generating full-stack apps from a prompt. Free tier plus paid plans from $20/month. See features and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bolt.new is an in-browser AI application builder created by StackBlitz, a company founded in 2017 by CEO Eric Simons and CTO Albert Pai and headquartered in San Francisco, California. StackBlitz had previously built a browser-based IDE for JavaScript frameworks and its underlying WebContainers technology, which runs a full Node.js runtime, package manager, and build process directly inside the browser without a remote server. Bolt.new, launched publicly on October 4, 2024, combines that WebContainers technology with large language models to let users describe an application in natural language and receive a complete, runnable full-stack web app, including frontend, backend, and dependencies, generated and executed entirely in the browser tab. Bolt.new grew unusually fast after launch, reportedly reaching around $20 million in annualized revenue within two months and roughly $40 million ARR within five months, making it one of the fastest-growing AI products at the time. The model originally powering code generation was Anthropic's Claude 3.5 Sonnet; StackBlitz has since expanded model support, including access to more advanced Claude models with adjustable reasoning depth. Pricing is token-based. The free tier provides 1 million daily tokens but does not allow exporting the generated project. Paid individual tiers are Pro at $20/month (10 million tokens/month), Pro 50 at $50/month (26 million tokens), Pro 100 at $100/month, and Pro 200 at $200/month, with higher tiers unlocking capabilities like GitHub export and custom domains; unused tokens on paid plans roll over for up to one additional month. Bolt.new also offers Teams pricing, billed per seat, where each paid member receives a monthly token allotment based on the subscription tier, enabling shared collaboration on projects. The platform integrates with Supabase for backend/database functionality, Netlify and Cloudflare for deployment, GitHub for version control and export, and Stripe for payments, positioning it to generate apps that are immediately deployable rather than just prototypes. Bolt.new targets both non-developers who want to turn an idea into a working app or website without writing code, and developers who want to rapidly scaffold full-stack projects and then continue editing the generated code by hand. Because the entire runtime executes client-side via WebContainers, projects can run and preview instantly without provisioning cloud infrastructure, though very large or resource-intensive projects can still hit browser performance limits. Bolt.new competes with other AI-assisted app-building tools and positions its browser-native execution model as its key technical differentiator. Eric Simons previously founded Thinkster, a code-education startup acquired by a private equity firm in December 2018, before co-founding StackBlitz with Albert Pai in 2017. In 2026, StackBlitz also made Bolt.new available through the AWS Marketplace, broadening its distribution to enterprise buyers that procure software through existing AWS billing relationships.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e82c60dd-a99b-47e5-b59b-e27db707e04e';

