-- ── Bonusly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bonusly is an employee recognition and rewards platform for peer-to-peer shoutouts, milestone celebrations, and AI-assisted people analytics.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Boulder, Colorado, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bonusly Review 2026: Employee Recognition Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Bonusly is a peer recognition and rewards platform with a free plan for up to 8 users and paid plans from $3/user/month. See features and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bonusly is an employee recognition and rewards software platform founded in 2012 by John Quinn and Raphael Crawford-Marks. The company is a remote-first organization headquartered in Boulder, Colorado, and has raised roughly $32.4 million in venture funding across five rounds. Bonusly is used by more than 3,400 organizations globally, including companies like DoorDash, Toast, and SeatGeek, to run peer-to-peer recognition programs where employees give each other small monetary bonuses ('bonuses' or points) tied to company values, which recipients can redeem for gift cards, charitable donations, or other rewards. The product integrates with everyday workplace tools, notably Slack and Microsoft Teams, so recognition can happen inside the channels employees already use, and it offers native iOS and Android mobile apps. Bonusly's pricing has three tiers. The Free plan supports up to 8 users and includes peer recognition, Slack/Teams integration, and mobile apps at no cost, making it accessible to very small teams. The Team plan is a per-user subscription: $3/user/month (or $30/user/year) for core recognition functionality with unlimited seats, or $5/user/month (or $50/user/year, with two months free on annual billing) for the same features plus the company's AI assistant, branded 'Bizy AI.' Team-tier features include advanced pulse-check analytics, automated milestone celebrations (birthdays, work anniversaries), HRIS integrations and user provisioning, 24/7 chat support, enhanced one-on-one meeting tools with AI-suggested agendas, and automated manager alerts. The top tier, Organization (with Bizy AI), uses custom quote-based pricing and adds company-wide announcements, structured awards and incentive programs, company-wide analytics, recognition-quality reporting, SAML single sign-on, a dedicated Customer Success Manager, a training library, and onboarding assistance. Bizy AI itself can also be purchased as a standalone add-on at roughly $2 per user per month after a trial period, and the Organization plan includes an allotment of AI/MCP tool calls (1,000 per month) with additional usage available. Bonusly is positioned for HR, people operations, and culture teams at small-to-mid-size and enterprise companies that want to embed regular, values-based peer recognition into daily workflows rather than relying solely on top-down annual reviews. Its emphasis on lightweight, frequent, values-tagged 'micro-bonuses' distinguishes it from broader HR suites, and its native chat-tool integrations make it well suited to distributed and remote-first teams. The vendor does not publicly disclose full custom Organization-tier pricing, which requires contacting sales for a quote. Bonusly's rewards catalog lets employees redeem accumulated points for options such as gift cards, charitable donations, and other curated rewards, giving recognition programs flexibility in how points translate into tangible value for recipients.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6806207d-501f-442f-81f0-3c146ec0fedc';

