-- ── BookStack ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BookStack is a free, open-source, self-hosted platform for organizing documentation and wikis into books, chapters, and pages.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BookStack: Free Open-Source Wiki & Documentation Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$BookStack is a free, self-hosted, open-source wiki platform for organizing documentation into books, chapters, and pages. MIT licensed and PHP/Laravel-based.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BookStack is a free, open-source, self-hosted platform for creating and organizing documentation and wiki content. It was created by Dan Brown, a UK-based web developer, with the first commit published on July 12, 2015, originally under the working name 'Oxbow' before being renamed BookStack within about two weeks. The project is built on PHP using the Laravel framework and is released under the MIT license, meaning it is free to download, self-host, and modify. BookStack organizes content using a distinct four-level hierarchy: shelves group related books, books contain chapters, chapters group pages, and pages hold the actual content. This structure is designed to mirror how physical reference material and manuals are organized, making it intuitive for teams building structured documentation rather than a flat wiki. Key platform capabilities include powerful full-text search with cross-book results, page revision history, image and file management, and a granular role-and-permission system that lets administrators control which users or groups can view, edit, or manage specific content. BookStack went through several years of beta development before its stable v21.04 release on April 9, 2021, after which the project has continued active maintenance. In early 2026, the canonical source repository moved from GitHub to Codeberg, with a GitHub mirror kept available for existing users. As of its tenth anniversary in July 2025, the project reported roughly 16,926 GitHub stars and 186 direct contributors, making it, by the maintainers' account, the most popular PHP-based wiki project on GitHub at that scale. BookStack has no official hosted SaaS offering or paid tier; organizations install it on their own server, container, or hosting environment (commonly via Docker) and are responsible for their own infrastructure, backups, and updates. Typical use cases include internal engineering wikis, IT knowledge bases, operational runbooks and standard operating procedures, onboarding documentation, and general reference material for technical and non-technical staff alike. It is commonly compared to and used as an open-source alternative to hosted tools like Confluence, Notion, or GitBook, appealing especially to organizations that want to keep documentation data entirely under their own control rather than in a third-party cloud service. Because it is community-maintained rather than backed by a company, BookStack has no formal company size, headquarters, or commercial support contract; support is provided through community documentation, forums, and the project repository rather than a dedicated vendor support team. The editor supports both a WYSIWYG mode and Markdown-based editing, giving technical and non-technical contributors different ways to create content within the same platform, and BookStack is commonly deployed via a maintained Docker image that simplifies installation, updates, and backups for self-hosting teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1c979afd-7472-4f90-be81-546475814887';

