INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Fee-free Standard checking$q$, $q$The Standard plan has no monthly fee, no minimum balance, and unlimited transactions.$q$, 0);
