INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$FDIC insurance up to $3M$q$, $q$Deposits are swept across partner banks for coverage well beyond the standard $250,000 limit.$q$, 3);
