INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Mobile banking apps$q$, $q$iOS and Android apps support mobile check deposit and account management on the go.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$QuickBooks integration$q$, $q$Sync transaction data with QuickBooks Online for easier bookkeeping.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$No monthly fee on the Standard checking plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Competitive APY compared to most traditional business banks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Fast, fully online line-of-credit application$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Up to $3 million in FDIC coverage through the partner bank sweep network$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Plus and Premier plans carry monthly fees unless waiver conditions are met$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$No physical branches for in-person banking$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Line of credit availability varies by state$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Bluevine is not itself a bank, so all deposits legally sit with a partner bank$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Is Bluevine a bank?$q$, $q$No. Bluevine is a financial technology company; banking services are provided by its partner, Coastal Community Bank, Member FDIC.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$What is Bluevine's highest APY?$q$, $q$Up to 3.00% APY on the Premier plan, applied to all balances up to $3 million.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Does Bluevine charge monthly fees?$q$, $q$The Standard checking plan is free. Plus ($30/month) and Premier ($95/month) fees can be waived by meeting balance or activity requirements.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$How much can I borrow with Bluevine's line of credit?$q$, $q$Bluevine offers business lines of credit up to $250,000, subject to eligibility and state availability.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$How is Bluevine FDIC-insured?$q$, $q$Deposits are swept across a network of partner banks, extending FDIC coverage up to $3,000,000 per depositor, above the standard $250,000 limit at a single bank.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Fee-free small business checking$q$, $q$Solopreneurs and startups open a Standard checking account to avoid monthly fees while still earning interest.$q$, $q$Solopreneurs and early-stage startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$High-yield cash management$q$, $q$Businesses holding larger operating balances upgrade to Plus or Premier to earn up to 3.00% APY on idle cash.$q$, $q$Established small businesses with cash reserves$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Working capital access$q$, $q$Businesses use Bluevine's line of credit to smooth cash flow gaps or fund short-term purchases without a traditional bank loan.$q$, $q$Small businesses needing flexible short-term financing$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Standard$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["No monthly fee","Up to 1.30% APY with activity requirement","Unlimited transactions","Mobile check deposit"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Plus$q$, $q$$30/month (waivable)$q$, $q$monthly$q$, NULL, $q$["1.75% APY up to $250,000","No activity requirement for interest","Discounts on payment fees"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$Premier$q$, $q$$95/month (waivable)$q$, $q$monthly$q$, NULL, $q$["3.00% APY on all balances up to $3 million","Advanced ACH debit controls","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bluevine is a financial technology company, founded in 2013 and headquartered in Redwood City, California, that provides online banking products for small businesses. Rather than holding its own bank charter, Bluevine partners with Coastal Community Bank, Member FDIC, to offer checking accounts, while extending FDIC coverage up to $3 million through a sweep network of partner banks.$q$, $q$The platform is built around Bluevine Business Banking, a fee-free-to-premium tiered checking account line, alongside a business line of credit product. It targets small business owners, freelancers, and startups who want digital-first banking with competitive interest on cash balances and fast access to working capital.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bluevine's checking accounts pay annual percentage yield on balances, ranging from 1.30% on the free Standard plan to 3.00% on the Premier plan, with no monthly fees required on Standard and fees waivable on the paid tiers when balance or activity conditions are met. All plans include unlimited transactions, no overdraft fees, mobile check deposit, and a business debit card.$q$, $q$The Premier plan adds advanced ACH debit controls so businesses can set thresholds and approve or block outgoing debits before they post. Bluevine also offers a revolving business line of credit of up to $250,000, bill pay for scheduling vendor payments, and integration with QuickBooks Online for bookkeeping. iOS and Android apps let owners manage banking from a mobile device.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bluevine checking has three tiers: Standard (free, up to 1.30% APY), Plus ($30/month, waivable, 1.75% APY), and Premier ($95/month, waivable, 3.00% APY on all balances up to $3 million). Monthly fees on Plus and Premier can typically be waived by meeting a minimum balance or deposit activity requirement, so many customers pay nothing.$q$, $q$The business line of credit is a separate product with its own draw and repayment terms rather than a flat subscription fee, and availability can vary by state and applicant eligibility.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7e483d96-1e11-493c-b7e9-c3b377066d91', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
