INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Embeddable e-signature API$q$, $q$REST API and SDKs let developers embed sending, signing, and webhooks directly into their own applications.$q$, 0);
