INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Bulk sending and signature links$q$, $q$Send documents to many recipients at once or generate shareable bulk signing links.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Complete audit trails$q$, $q$Every signing action is logged and available as a downloadable audit trail report.$q$, 3);
