INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$SSO and custom roles$q$, $q$Business and Premium plans support single sign-on and granular user permissions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Compliance coverage$q$, $q$Meets ESIGN, eIDAS, SOC 2, GDPR, HIPAA, and PCI DSS requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Salesforce integration$q$, $q$Business plan connects BoldSign signing workflows to Salesforce.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Free tier covers up to 25 envelopes per month for individuals and micro-businesses$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Developer-first API pricing is competitive against per-seat-only competitors$q$, 1);
