INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Unlimited envelopes require the $15+/user/month Business tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$API pricing can add up per envelope at high volume$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Advanced compliance features like HIPAA are gated behind higher tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Brand recognition is lower than incumbents like DocuSign$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Does BoldSign have a free plan?$q$, $q$Yes, the Essential plan is free and includes up to 25 envelopes per month and 2 templates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Can BoldSign be embedded into another application?$q$, $q$Yes, BoldSign offers a REST API and SDKs specifically designed for embedding signing workflows into third-party software.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Is BoldSign HIPAA compliant?$q$, $q$Yes, HIPAA compliance is available on the Business plan and above.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$How much does the BoldSign API cost?$q$, $q$The Enterprise API is billed at $0.75 per envelope with a $30/month minimum covering 40 envelopes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Who makes BoldSign?$q$, $q$BoldSign is developed by Syncfusion, a software component and developer tools company founded in 2001.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Standalone contract signing$q$, $q$Businesses send and track signature requests for contracts, offer letters, and agreements from the BoldSign web app.$q$, $q$Small and mid-size businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Embedded signing in SaaS products$q$, $q$Software companies use the BoldSign API to add native e-signature capability inside their own platform.$q$, $q$SaaS developers and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Regulated document workflows$q$, $q$Healthcare and finance teams use HIPAA- and SOC 2-compliant signing for sensitive documents.$q$, $q$Healthcare and financial services teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Essential$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["25 envelopes/month","2 templates","Audit trail","Signer authentication"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Growth$q$, $q$$5/user/month (annual)$q$, $q$annual or monthly$q$, NULL, $q$["50 envelopes/user/month","10 templates","Team management","In-person signing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Business$q$, $q$$15/user/month (annual)$q$, $q$annual or monthly$q$, NULL, $q$["Unlimited envelopes","SSO","HIPAA compliance","Salesforce integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Premium$q$, $q$$99/month (annual)$q$, $q$annual or monthly$q$, NULL, $q$["Unlimited senders and users","250 envelopes/month included"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$Enterprise API$q$, $q$$0.75/envelope, $30/month minimum$q$, $q$usage-based$q$, NULL, $q$["Embedded requesting and signing","Webhooks","40 envelopes included in minimum"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BoldSign is an electronic signature platform launched in 2021 by Syncfusion, a developer tools company founded in 2001 and headquartered in Research Triangle Park, North Carolina. BoldSign was designed from the ground up to be embeddable into other software products through SDKs and a REST API, while also functioning as a standalone e-signature web app.$q$, $q$The platform targets both end-user businesses that need to send and sign contracts, and software teams that want to build native document-signing workflows into their own applications without routing users to a separate signing service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BoldSign supports reusable templates, bulk sending, bulk signature links, custom branding, and document categorization for tracking sent and received envelopes. Every signature event is captured in a complete audit trail, and completed documents are digitally signed to prevent tampering.$q$, $q$Higher tiers add single sign-on (SSO), custom user roles, HIPAA compliance, AI-powered document capabilities, and Salesforce integration. BoldSign complies with the U.S. ESIGN Act, eIDAS, SOC 2, GDPR, HIPAA, and PCI DSS, making it viable for regulated industries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BoldSign's web app has four tiers: Essential (free, 25 envelopes/month), Growth ($5/user/month annual), Business ($15/user/month annual, unlimited envelopes, SSO, HIPAA), and Premium ($99/month annual, unlimited senders). Monthly billing is available at a higher per-month rate on paid tiers.$q$, $q$Developers integrating signing directly into their own product can instead use the Enterprise API, billed at $0.75 per envelope with a $30/month minimum covering 40 envelopes.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('de8338ea-b5f1-466f-9506-f229d3f662f7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
