INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Traditional or headless CMS$q$, $q$Run Bolt as a standard server-rendered site or expose content via API-Platform for a decoupled frontend.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Symfony and Twig foundation$q$, $q$Built on Symfony components, Doctrine ORM, and the Twig templating engine.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Multi-database support$q$, $q$Works with SQLite, MySQL, or PostgreSQL.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Composer-based extensions$q$, $q$Extend functionality using packages installed through Composer.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Multilingual editor$q$, $q$The content editor interface is available in roughly 15 languages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Self-hosted deployment$q$, $q$Full control over hosting, data, and server configuration since there is no vendor SaaS lock-in.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Completely free and open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Lightweight compared to larger PHP CMS platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Flexible headless/decoupled mode via API-Platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Built on well-known Symfony and Twig components familiar to PHP developers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$No official hosted/SaaS version; requires self-hosting and server management$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Smaller plugin/theme ecosystem than WordPress or Drupal$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$No dedicated commercial support plan; relies on community help$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Requires PHP and Symfony familiarity to extend effectively$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Is Bolt CMS free?$q$, $q$Yes, Bolt CMS is fully open source under the MIT license with no licensing cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Can Bolt CMS be used as a headless CMS?$q$, $q$Yes, Bolt supports a headless/decoupled mode via API-Platform in addition to traditional server-rendered output.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$What is Bolt CMS built with?$q$, $q$Bolt is built in PHP on Symfony components, Doctrine, and Twig, and supports SQLite, MySQL, or PostgreSQL.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Who maintains Bolt CMS today?$q$, $q$Following founder Bob den Otter's death in January 2024, the Dutch agency Ontwerpwerk acquired steward agency Two Kings to continue the project alongside community contributors.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Do I need to host Bolt CMS myself?$q$, $q$Yes, Bolt is self-hosted; there is no official managed cloud version, so you install it on your own server or hosting provider.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Agency-built marketing sites$q$, $q$Web agencies use Bolt to build and maintain lightweight, content-driven client websites.$q$, $q$Web development agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Headless content backend$q$, $q$Developers pair Bolt's headless mode with a separate frontend framework for a decoupled architecture.$q$, $q$Developers building custom frontends$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$Open Source / Self-Hosted$q$, $q$Free$q$, $q$one-time (self-hosted)$q$, NULL, $q$["Full CMS source code","MIT license","Community support","Composer extension ecosystem"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bolt CMS is an open-source, self-hosted content management system written in PHP. It was created in 2012 by Bob den Otter, a Dutch developer based in The Hague, as a lightweight alternative to larger CMS platforms, and is built on Symfony components, Doctrine, and the Twig templating engine.$q$, $q$Bolt can run as a traditional server-rendered CMS or as a headless CMS via API-Platform, and it supports SQLite, MySQL, or PostgreSQL as its database backend. The project is MIT licensed, with no cost to download, install, or run.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bolt offers a content editor available in around 15 languages, an extension system built on Composer packages, and support for custom code to adapt the CMS to specific project needs. Its headless mode exposes content through an API for use with any frontend framework.$q$, $q$Because it is self-hosted, teams control their own server environment, data, and hosting costs. The current supported release line is Bolt 6.x; older Bolt 3.x/4.x releases are considered legacy.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bolt CMS is free and open source under the MIT license. There are no paid tiers, subscriptions, or per-seat fees for the software itself; the only costs are self-managed hosting and any paid third-party extensions a team chooses to add.$q$, $q$Support is community-driven through documentation and the project's GitHub/Codeberg repositories rather than a commercial support contract, since Bolt has no official enterprise pricing plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddf71270-678f-48af-a74a-407a4c5982bb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Prompt-to-app generation$q$, $q$Describe an application in natural language and receive a complete, runnable full-stack project.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$In-browser WebContainers execution$q$, $q$Runs Node.js, the package manager, and build process entirely in the browser without provisioning a server.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Supabase integration$q$, $q$Connects generated apps to Supabase for database, auth, and backend functionality.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$GitHub export$q$, $q$Export generated projects to GitHub on paid plans for continued development.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$One-click deployment$q$, $q$Deploy generated apps via Netlify or Cloudflare integrations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Stripe integration$q$, $q$Add payments to generated apps through built-in Stripe support.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Multi-model support$q$, $q$Uses Claude models, including newer versions with adjustable reasoning depth.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Team collaboration$q$, $q$Teams plans give a shared workspace with per-seat token allotments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Generates and runs complete full-stack apps entirely in the browser, no local setup required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Free tier available to try the product before subscribing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Native integrations with Supabase, GitHub, Netlify, Stripe, and Cloudflare$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Fast iteration through conversational refinement of generated code$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Free tier does not allow exporting the generated project$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Token-based pricing can be hard to predict for larger or more complex projects$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Browser-based execution can hit performance limits on very large projects$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Higher usage tiers ($50-$200/month) are needed for serious ongoing development$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Is Bolt.new free to use?$q$, $q$Yes, there is a free tier with 1 million daily tokens, though it does not allow project export.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Who built Bolt.new?$q$, $q$Bolt.new was built by StackBlitz, founded in 2017 by Eric Simons and Albert Pai, and launched publicly in October 2024.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$What AI model powers Bolt.new?$q$, $q$Bolt.new originally used Anthropic's Claude 3.5 Sonnet and has since added support for newer Claude models with adjustable reasoning depth.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Does Bolt.new require installing software?$q$, $q$No, apps run entirely in the browser using StackBlitz's WebContainers technology, so no local Node.js or server setup is needed.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Can Bolt.new deploy apps directly?$q$, $q$Yes, it integrates with Netlify and Cloudflare for deployment, plus GitHub for exporting code on paid plans.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Rapid prototyping$q$, $q$Founders and product teams turn an idea into a working full-stack prototype from a single prompt.$q$, $q$Founders and product managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$No-code app building$q$, $q$Non-developers build functional web apps and internal tools without writing code manually.$q$, $q$Non-technical builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Developer scaffolding$q$, $q$Developers use Bolt.new to quickly scaffold a full-stack project structure, then continue editing by hand.$q$, $q$Software developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["1 million daily tokens","No project export"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Pro$q$, $q$$20/month$q$, $q$monthly$q$, NULL, $q$["10 million tokens/month","GitHub export","Custom domains"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Pro 50$q$, $q$$50/month$q$, $q$monthly$q$, NULL, $q$["26 million tokens/month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Pro 100$q$, $q$$100/month$q$, $q$monthly$q$, NULL, $q$["Higher monthly token allotment"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Pro 200$q$, $q$$200/month$q$, $q$monthly$q$, NULL, $q$["Highest individual monthly token allotment"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bolt.new is an AI-powered app builder from StackBlitz, a company founded in 2017 by Eric Simons and Albert Pai and based in San Francisco. It launched publicly on October 4, 2024, and lets users describe an app in plain language to generate a complete, runnable full-stack web application.$q$, $q$The defining technical feature is that the generated app runs entirely inside the browser via StackBlitz's WebContainers technology, which executes a full Node.js runtime, package manager, and build process client-side rather than on a remote server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bolt.new generates frontend, backend, and dependency code from a single prompt and lets users continue refining the app through further chat instructions or direct code edits. It integrates with Supabase for backend and database needs, GitHub for version control and export, Netlify and Cloudflare for deployment, and Stripe for payments.$q$, $q$The platform has expanded its context handling to support significantly larger projects than at launch, and added access to newer models, including Claude models with adjustable reasoning depth, alongside the original Claude 3.5 Sonnet.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bolt.new uses token-based pricing. The free tier includes 1 million daily tokens but no project export. Paid individual plans are Pro ($20/month, 10M tokens/month), Pro 50 ($50/month, 26M tokens), Pro 100 ($100/month), and Pro 200 ($200/month), with unused tokens rolling over for one additional month.$q$, $q$Teams pricing is billed per seat, with each paid member receiving a monthly token allotment based on the chosen subscription tier, enabling shared collaborative projects.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
