INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Peer-to-peer recognition$q$, $q$Employees give each other values-tagged bonuses that can be redeemed for rewards.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Slack and Microsoft Teams integration$q$, $q$Recognition happens directly inside the chat tools employees already use.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Automated milestone celebrations$q$, $q$Birthdays and work anniversaries are recognized automatically.$q$, 2);
