INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Pulse-check analytics$q$, $q$Advanced engagement analytics track recognition trends across the organization.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$HRIS integrations and provisioning$q$, $q$Sync employee data automatically from HR systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Awards and incentive programs$q$, $q$Organization-tier tools for running structured, company-wide recognition campaigns.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Mobile apps$q$, $q$Native iOS and Android apps for recognizing coworkers on the go.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Free plan available for teams up to 8 users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Deep native integration with Slack and Microsoft Teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Flexible per-user pricing that scales from small teams to enterprises$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$AI-assisted features like automated recaps and manager alerts$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Organization-tier pricing is not publicly disclosed and requires a sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Bizy AI features require an add-on or higher-tier plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Redeemable rewards depend on program budget set by the employer$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Advanced analytics and SSO are gated to higher-priced tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Does Bonusly have a free plan?$q$, $q$Yes, the Free plan supports up to 8 users with core peer recognition and Slack/Teams integration.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$How much does Bonusly cost per user?$q$, $q$The Team plan is $3/user/month without AI features or $5/user/month with Bizy AI included; Organization pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$What is Bizy AI?$q$, $q$Bizy AI is Bonusly's AI assistant that provides pulse analytics, meeting agenda suggestions, automated recaps, and manager alerts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Who founded Bonusly?$q$, $q$Bonusly was founded in 2012 by John Quinn and Raphael Crawford-Marks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Does Bonusly integrate with Slack?$q$, $q$Yes, Bonusly integrates natively with both Slack and Microsoft Teams so recognition happens in existing chat channels.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Peer recognition programs$q$, $q$HR and culture teams roll out ongoing peer-to-peer recognition tied to company values.$q$, $q$HR and people operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Remote and distributed team culture$q$, $q$Distributed companies use Slack/Teams-native recognition to keep culture visible without in-person interaction.$q$, $q$Remote-first companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Manager insight and coaching$q$, $q$Managers use Bizy AI-suggested agendas and automated recaps to run better one-on-ones.$q$, $q$People managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 8 users","Peer recognition","Slack and Teams integration","iOS and Android apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Team$q$, $q$$3/user/month ($5 with Bizy AI)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited seats","Pulse check analytics","HRIS integrations","24/7 chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$Organization + Bizy AI$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Company-wide announcements","Awards and incentives","SAML SSO","Dedicated Customer Success Manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bonusly is an employee recognition and rewards platform founded in 2012 by John Quinn and Raphael Crawford-Marks. The remote-first company is headquartered in Boulder, Colorado, and serves more than 3,400 organizations, including DoorDash, Toast, and SeatGeek.$q$, $q$The platform centers on peer-to-peer recognition: employees give each other points or small monetary bonuses tied to company values, which recipients redeem for gift cards, donations, or other rewards, all surfaced inside Slack or Microsoft Teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bonusly offers values-based peer recognition, automated milestone celebrations for birthdays and work anniversaries, pulse-check surveys and analytics, and HRIS integrations with automated user provisioning. Its Bizy AI assistant adds AI-suggested one-on-one meeting agendas, automated performance recaps, and manager alerts.$q$, $q$Higher tiers add company-wide announcements, structured awards and incentive campaigns, recognition-quality reporting, and SAML SSO, along with a dedicated Customer Success Manager for larger organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bonusly's Free plan covers up to 8 users with core recognition and chat-tool integrations. The Team plan is $3/user/month without Bizy AI or $5/user/month with Bizy AI included (annual billing discounts apply), covering unlimited seats and advanced analytics.$q$, $q$The Organization plan is custom-priced and adds company-wide features and dedicated support. Bizy AI can also be added standalone at roughly $2/user/month after a trial.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
