INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6806207d-501f-442f-81f0-3c146ec0fedc', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Books, chapters, and pages structure$q$, $q$Content is organized hierarchically into shelves, books, chapters, and pages for structured documentation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Full-text search$q$, $q$Powerful cross-book search helps users find content quickly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Page revisions$q$, $q$Tracks page history so changes can be reviewed or reverted.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Role and permission system$q$, $q$Granular access controls restrict viewing, editing, or managing content by user or role.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Image and file management$q$, $q$Built-in handling for uploading and managing images and attachments within pages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Self-hosted deployment$q$, $q$Runs on your own server or via Docker, keeping documentation data fully under your control.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Completely free and open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Intuitive books/chapters/pages structure suited to reference documentation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Active community with frequent updates and a large contributor base$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Full control over data since it is fully self-hosted$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$No official hosted/SaaS version; requires self-managed hosting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$No commercial support contract available from the project itself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Fewer built-in integrations than commercial wiki tools like Confluence$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Requires basic server administration knowledge to install and maintain$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Is BookStack free?$q$, $q$Yes, BookStack is fully open source under the MIT license with no cost to use.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Who created BookStack?$q$, $q$BookStack was created by UK developer Dan Brown, starting in July 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Does BookStack require hosting it myself?$q$, $q$Yes, BookStack is self-hosted; there is no official managed cloud version, though it is commonly deployed via Docker.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$What technology is BookStack built on?$q$, $q$BookStack is built in PHP using the Laravel framework.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$How is content organized in BookStack?$q$, $q$Content follows a four-level hierarchy: shelves group books, books contain chapters, and chapters group pages.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Internal engineering wikis$q$, $q$Engineering teams document architecture, runbooks, and processes in a structured, searchable wiki.$q$, $q$Engineering and IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Knowledge base and onboarding docs$q$, $q$Organizations build reference documentation and onboarding guides for new employees.$q$, $q$Operations and HR teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$Open Source / Self-Hosted$q$, $q$Free$q$, $q$one-time (self-hosted)$q$, NULL, $q$["Full platform source code","MIT license","Community support","Docker deployment supported"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BookStack is a free, open-source, self-hosted documentation and wiki platform created by UK developer Dan Brown, with its first commit dating to July 12, 2015. It is built on PHP and Laravel, and released under the MIT license.$q$, $q$Content is organized into a four-level hierarchy of shelves, books, chapters, and pages, designed to mirror how reference manuals are structured, which distinguishes it from flat-page wiki tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BookStack includes full-text search across books, page revision history, image and file management, and a role-and-permission system for controlling access at a granular level. The editor supports both WYSIWYG and Markdown editing.$q$, $q$The project reached stable status with its v21.04 release in April 2021 after several years of beta development, and by its tenth anniversary in July 2025 had accumulated nearly 17,000 GitHub stars and around 186 direct contributors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1c979afd-7472-4f90-be81-546475814887', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BookStack is completely free and open source under the MIT license. There is no official paid tier, subscription, or hosted SaaS product; organizations self-host it, commonly using Docker, and pay only for their own infrastructure.$q$, $q$Support comes from community documentation, the project repository, and community forums rather than a commercial vendor support contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c979afd-7472-4f90-be81-546475814887', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c979afd-7472-4f90-be81-546475814887', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1c979afd-7472-4f90-be81-546475814887', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Local recording with cloud backup$q$, $q$Each participant is recorded locally and uploaded as a separate track, protecting against connection drops.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Up to 4K video and lossless audio$q$, $q$Supports high-resolution video and 48kHz lossless audio recording.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Multistream livestreaming$q$, $q$Stream live to YouTube, Facebook, LinkedIn, Twitch, and more simultaneously.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Transcript-based editing$q$, $q$Edit recordings by editing the transcript text to remove silences or unwanted sections.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Real-time captions$q$, $q$Auto-generated closed captions available in over 30 languages during live sessions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Producer mode$q$, $q$Monitor a session silently without appearing in the recording.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Custom branding$q$, $q$Apply logos, colors, and backgrounds to match a show's identity.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Multi-show and team management$q$, $q$Manage multiple shows, users, and roles for networks running several podcasts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Local per-participant recording protects quality from unstable internet connections$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Simultaneous multistreaming to several platforms at once$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Transcript-based editing speeds up post-production$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Guests join with a simple link, no software installation required$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Hourly overage charges can increase costs for high-volume creators$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$No published free plan, only a free trial$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Enterprise features like SSO and SOC 2 require custom pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Smaller brand recognition than larger podcasting platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$How much does Boomcaster cost?$q$, $q$Plans start at $20/month for the Starter tier (5 hours), with Indie at $45/month (15 hours) and Pro at $75/month (30 hours).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Does Boomcaster offer a free trial?$q$, $q$Yes, a free trial is available so users can test recording and livestreaming before subscribing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Can Boomcaster livestream to multiple platforms at once?$q$, $q$Yes, it supports simultaneous multistreaming to destinations like YouTube, Facebook, LinkedIn, and Twitch.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$What video and audio quality does Boomcaster support?$q$, $q$Up to 4K video and lossless 48kHz audio, with each participant recorded as a separate local track.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Who founded Boomcaster?$q$, $q$Boomcaster was founded in 2020 by Hari Gopalakrishna in Chapel Hill, North Carolina.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Remote podcast recording$q$, $q$Hosts record interviews with remote guests while protecting audio/video quality from connection issues.$q$, $q$Podcast hosts and producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Live multistreaming$q$, $q$Creators broadcast episodes live to multiple social platforms simultaneously while capturing a high-quality recording.$q$, $q$Video creators and livestreamers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Podcast network production$q$, $q$Production teams manage multiple shows, hosts, and team roles from one account.$q$, $q$Podcast networks and production teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Starter$q$, $q$$20/month$q$, $q$monthly$q$, NULL, $q$["5 hours of recording/livestreaming","$4.20 per additional hour"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Indie$q$, $q$$45/month$q$, $q$monthly$q$, NULL, $q$["15 hours of recording/livestreaming","$3.60 per additional hour"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Pro$q$, $q$$75/month$q$, $q$monthly$q$, NULL, $q$["30 hours of recording/livestreaming","$3.00 per additional hour"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["SSO/SAML integration","SOC2 compliance","Custom infrastructure","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Boomcaster is a remote recording and livestreaming platform for podcasters and video creators, founded in 2020 by Hari Gopalakrishna and headquartered in Chapel Hill, North Carolina. It was built to solve a common problem in remote podcasting: recording quality degrading due to a guest's unstable internet connection.$q$, $q$Each participant's audio and video is captured locally on their own device and uploaded as an independent track, so the final recording is protected from connection drops or lag during the session, while the platform simultaneously supports live multistreaming to social platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Boomcaster supports up to 4K video and lossless 48kHz audio with multi-track recording, plus simultaneous live streaming to YouTube, Facebook, LinkedIn, and Twitch. Automated transcripts and real-time captions are available in more than 30 languages.$q$, $q$Transcript-based editing lets creators cut silences and awkward pauses by editing text rather than a waveform, and producer mode allows a silent monitor to join a session without appearing in the recording. The platform also supports managing multiple shows and team roles.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Boomcaster's plans are Starter ($20/month, 5 hours, $4.20/extra hour), Indie ($45/month, 15 hours, $3.60/extra hour), and Pro ($75/month, 30 hours, $3.00/extra hour), with annual billing giving 12 months for the price of 10.$q$, $q$An Enterprise tier offers custom pricing with SSO/SAML, SOC 2 compliance, and dedicated support, and a free trial is available on the standard plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('365cb646-7629-4791-a92b-ebcb79d3c233', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Drag-and-drop page builder$q$, $q$Assemble pages visually from a library of Bootstrap components without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Bootstrap 3, 4, and 5 support$q$, $q$Build projects on any of the three major Bootstrap framework versions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Offline desktop app$q$, $q$Runs fully offline on Windows, macOS, and Linux, storing projects as local files.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$CSS animations$q$, $q$Create scroll- and hover-triggered animations, including Lottie animation support.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Google Fonts and icon libraries$q$, $q$Built-in access to Google Fonts and multiple vector icon sets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Real-time preview$q$, $q$See layout and styling changes reflected instantly while editing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Responsive, SEO-friendly output$q$, $q$Exported sites are optimized to be fast, responsive, and search-friendly.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$One-time $29 price with lifetime access, no recurring subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Fully offline desktop app with no internet dependency$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Exports clean, standard, editable Bootstrap HTML/CSS$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Cross-platform support for Windows, macOS, and Linux$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$No built-in real-time collaboration since it is a single-user desktop app$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$No native hosting; sites must be deployed separately$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Small independent developer team behind the product$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$No mobile app for editing on tablets or phones$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$How much does Bootstrap Studio cost?$q$, $q$Bootstrap Studio is a one-time purchase of $29 that includes lifetime access and all future minor updates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Is Bootstrap Studio a subscription?$q$, $q$No, it uses a one-time-purchase license rather than a recurring subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$What platforms does Bootstrap Studio support?$q$, $q$It runs natively on Windows, macOS, and Linux as a desktop application built on Electron.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Which Bootstrap versions does it support?$q$, $q$Bootstrap Studio supports Bootstrap 3, 4, and 5.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Who makes Bootstrap Studio?$q$, $q$Bootstrap Studio is developed by Zine EOOD, a small software company based in Varna, Bulgaria, founded by Martin Angelov.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$No-code landing page design$q$, $q$Designers build responsive landing pages and marketing sites visually without writing HTML/CSS.$q$, $q$Freelance designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Agency website prototyping$q$, $q$Small agencies use Bootstrap Studio to quickly prototype and hand off Bootstrap-based site designs to developers.$q$, $q$Small web design agencies$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$Lifetime License$q$, $q$$29$q$, $q$one-time$q$, NULL, $q$["Lifetime access","All future minor updates","Template and component library","No usage limits"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bootstrap Studio is a desktop application for visually building responsive websites with the Bootstrap framework, developed by Zine EOOD, a small independent software company based in Varna, Bulgaria, and launched on October 19, 2015.$q$, $q$Built on Electron, it runs natively on Windows, macOS, and Linux, works fully offline, and stores each project as a local .bsdesign file rather than depending on a cloud service or internet connection.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The app is built around a drag-and-drop editor with a library of pre-built Bootstrap components such as headers, footers, navigation bars, forms, and image galleries, adjustable through visual controls. It supports Bootstrap 3, 4, and 5.$q$, $q$Additional capabilities include built-in Google Fonts, multiple icon libraries, scroll- and hover-triggered CSS animations, Lottie animation support, parallax backgrounds, and a real-time preview that reflects edits instantly.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3a32c2e6-fe5a-4065-bfb8-918758329971', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Bootstrap Studio uses a one-time-purchase model: a single $29 payment provides a lifetime license, all future minor updates, and access to the built-in template and component library, with no subscription or recurring fee.$q$, $q$This differs from most modern web design tools that use monthly or annual subscription pricing, making Bootstrap Studio a lower total-cost option for users who plan to use it long-term.$q$]::text[], 2);
